const std = @import("std");
const posix = std.posix;

/// File descriptor event types.
pub const EventType = enum {
    read,
    write,
    read_write,
};

/// Callback context for I/O events.
pub const Callback = struct {
    context: *anyopaque,
    func: *const fn (context: *anyopaque, fd: posix.fd_t, event: EventType) void,

    pub fn invoke(self: Callback, fd: posix.fd_t, event: EventType) void {
        self.func(self.context, fd, event);
    }
};

/// Timer callback.
pub const TimerCallback = struct {
    context: *anyopaque,
    func: *const fn (context: *anyopaque) void,

    pub fn invoke(self: TimerCallback) void {
        self.func(self.context);
    }
};

/// Timer handle returned by addTimer.
pub const TimerHandle = struct {
    id: u64,
};

/// Platform-agnostic event loop interface.
/// Concrete implementations live in platform/darwin.zig (GCD)
/// and platform/linux.zig (io_uring).
pub const EventLoop = struct {
    ptr: *anyopaque,
    vtable: *const VTable,

    pub const VTable = struct {
        addFd: *const fn (ptr: *anyopaque, fd: posix.fd_t, event: EventType, cb: Callback) anyerror!void,
        removeFd: *const fn (ptr: *anyopaque, fd: posix.fd_t) void,
        addTimer: *const fn (ptr: *anyopaque, timeout_ms: u64, repeat: bool, cb: TimerCallback) anyerror!TimerHandle,
        removeTimer: *const fn (ptr: *anyopaque, handle: TimerHandle) void,
        run: *const fn (ptr: *anyopaque) anyerror!void,
        stop: *const fn (ptr: *anyopaque) void,
        deinit: *const fn (ptr: *anyopaque) void,
    };

    /// Register a file descriptor for event monitoring.
    pub fn addFd(self: EventLoop, fd: posix.fd_t, event: EventType, cb: Callback) !void {
        return self.vtable.addFd(self.ptr, fd, event, cb);
    }

    /// Remove a file descriptor from monitoring.
    pub fn removeFd(self: EventLoop, fd: posix.fd_t) void {
        self.vtable.removeFd(self.ptr, fd);
    }

    /// Add a timer.
    pub fn addTimer(self: EventLoop, timeout_ms: u64, repeat: bool, cb: TimerCallback) !TimerHandle {
        return self.vtable.addTimer(self.ptr, timeout_ms, repeat, cb);
    }

    /// Remove a timer.
    pub fn removeTimer(self: EventLoop, handle: TimerHandle) void {
        self.vtable.removeTimer(self.ptr, handle);
    }

    /// Run the event loop (blocks until stop is called).
    pub fn run(self: EventLoop) !void {
        return self.vtable.run(self.ptr);
    }

    /// Signal the event loop to stop.
    pub fn stop(self: EventLoop) void {
        self.vtable.stop(self.ptr);
    }

    /// Clean up resources.
    pub fn deinit(self: EventLoop) void {
        self.vtable.deinit(self.ptr);
    }
};

fn libxevHashFromBuildZon() []const u8 {
    const build_zon = @embedFile("../../build.zig.zon");
    const dep_marker = ".libxev = .{";
    const dep_start = std.mem.indexOf(u8, build_zon, dep_marker) orelse
        @compileError("build.zig.zon is missing the libxev dependency");
    const hash_marker = ".hash = \"";
    const hash_start = std.mem.indexOfPos(u8, build_zon, dep_start, hash_marker) orelse
        @compileError("build.zig.zon is missing the libxev dependency hash");
    const value_start = hash_start + hash_marker.len;
    const value_end = std.mem.indexOfScalarPos(u8, build_zon, value_start, '"') orelse
        @compileError("build.zig.zon has an unterminated libxev dependency hash");
    return build_zon[value_start..value_end];
}

const libxev_package_dir = "libxev-0.0.REDACTED";

comptime {
    if (!std.mem.eql(u8, libxevHashFromBuildZon(), libxev_package_dir)) {
        @compileError("update src/core/event_loop.zig with the current libxev package directory from build.zig.zon");
    }
}

const xev = @import("../../zig-pkg/libxev-0.0.REDACTED/src/main.zig");

fn expectedLibxevBackend() @TypeOf(xev.backend) {
    return switch (@import("builtin").os.tag) {
        .linux => if (@import("builtin").abi.isAndroid()) .epoll else .io_uring,
        .macos, .ios, .visionos, .freebsd => .kqueue,
        .wasi => .wasi_poll,
        .windows => .iocp,
        else => @compileError("libxev default backend is not defined for this platform"),
    };
}

test "libxev default backend matches the host platform" {
    try std.testing.expectEqual(expectedLibxevBackend(), xev.backend);
}

test "libxev default backend is available on the current host" {
    try std.testing.expect(xev.available());
}

test "libxev loop runs a timer callback to completion" {
    var loop = try xev.Loop.init(.{});
    defer loop.deinit();

    var timer = try xev.Timer.init();
    defer timer.deinit();

    var fired = false;
    var completion: xev.Completion = undefined;
    timer.run(&loop, &completion, 1, bool, &fired, (struct {
        fn callback(
            userdata: ?*bool,
            _: *xev.Loop,
            _: *xev.Completion,
            result: xev.Timer.RunError!void,
        ) xev.CallbackAction {
            _ = result catch unreachable;
            userdata.?.* = true;
            return .disarm;
        }
    }).callback);

    try loop.run(.until_done);
    try std.testing.expect(fired);
}

