const std = @import("std");

pub fn main() !void {
    var gpa_state: std.heap.DebugAllocator(.{}) = .init;
    defer _ = gpa_state.deinit();
    const gpa = gpa_state.allocator();

    var threaded: std.Io.Threaded = .init(gpa, .{});
    defer threaded.deinit();
    const io = threaded.io();

    const path = "/tmp/zmux-std-io-probe.sock";
    std.fs.deleteFileAbsolute(path) catch {};

    const ua = try std.Io.net.UnixAddress.init(path);
    var server = try ua.listen(io, .{});
    defer server.deinit(io);

    const accept_thread = try std.Thread.spawn(.{}, struct {
        fn run(s: *std.Io.net.Server, io_arg: std.Io) !void {
            var stream = try s.accept(io_arg);
            defer stream.close(io_arg);
            var buf: [16]u8 = undefined;
            var reader = stream.reader(io_arg, &buf);
            const msg = try reader.interface.takeDelimiterExclusive('\n');
            std.debug.print("accepted:{s}\n", .{msg});
        }
    }.run, .{&server, io});
    defer accept_thread.join();

    var client = try ua.connect(io);
    defer client.close(io);
    var wbuf: [16]u8 = undefined;
    var writer = client.writer(io, &wbuf);
    try writer.interface.writeAll("hello\n");
    try writer.interface.flush();
}
